async (params, browser) => {
  // Search eBay
  await browser.open(`https://www.ebay.com/sch/i.html?_nkw=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.srp-results .s-item, .srp-river-results .s-item, li.s-item, li.s-card', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.srp-results .s-item, .srp-river-results .s-item, li.s-item, li.s-card'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const isCard = el.classList.contains('s-card'); const titleEl = el.querySelector(isCard ? '.s-card__title' : '.s-item__title, .s-item__title span'); const linkEl = el.querySelector(isCard ? '.s-card__title a, a' : '.s-item__link, a.s-item__link'); const priceEl = el.querySelector(isCard ? '.s-card__price' : '.s-item__price, .s-item__price span.POSITIVE, .s-item__price span.BOLD'); const shippingEl = el.querySelector(isCard ? '.s-card__shipping' : '.s-item__shipping, .s-item__freeXDays, .s-item__logisticsCost'); const conditionEl = el.querySelector(isCard ? '.s-card__subtitle' : '.SECONDARY_INFO, .s-item__subtitle span'); const bidsEl = el.querySelector('.s-item__bidCount, .s-item__bids'); const timeLeftEl = el.querySelector('.s-item__time-left, .s-item__time'); const imgEl = el.querySelector(isCard ? '.s-card__image img' : '.s-item__image-wrapper img, .s-item__image img'); const sellerEl = el.querySelector('.s-item__seller-info-text, .s-item__seller-info a'); const formatEl = el.querySelector('.s-item__purchase-options, .s-item__detail--primary .BOLD'); const title = titleEl ? titleEl.textContent.trim() : ''; if (!title || title === 'Shop on eBay' || title === 'Results matching fewer words') continue; results.push({ title: title, price: priceEl ? priceEl.textContent.trim() : '', shipping: shippingEl ? shippingEl.textContent.trim() : '', condition: conditionEl ? conditionEl.textContent.trim() : '', bids: bidsEl ? bidsEl.textContent.trim() : '', time_left: timeLeftEl ? timeLeftEl.textContent.trim() : '', format: formatEl ? formatEl.textContent.trim() : '', seller: sellerEl ? sellerEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? linkEl.href : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
